    @lru_cache(maxsize=None)
    def g(x, m, j): return sum(g(x//(prime(m)**i), m-1, i) for i in range(1,min(j-1,integer_log(x, prime(m))[0])+1)) if m-1 else min(j,x.bit_length())-1
